from src.nodes.base import BaseNode

class Message_Node(BaseNode):
    name = "message_node"

    def __init__(self):
        super().__init__()        # [AUTO-GENERATED-PORTS-START]
        self.add_input("msg", "string", widget_type="text")
        self.add_output("out", "string")
        # [AUTO-GENERATED-PORTS-END]

    def on_parameter_changed(self, name, value):
        if name == "msg":
            self.parameters["out"] = value
    def on_unplug_sync(self, port_name, is_input):
        self.log_info(f"Disconnected {port_name}")


    async def execute(self, inputs):
        msg = str(inputs.get("msg", ""))
        print(f"MESSAGE: {msg}")
        return {"out": msg}

def register_node():
    return Message_Node
